export const RFQ_STATUS_FIELD = 'Status';
export const RFQ_TECH_PACK_LINK_FIELD = 'Tech Pack Link';
export const RFQ_ACTIVE_STATUS_ID = 1;
export const RFQ_ACTIVE_STATUS_TITLE = 'Active';

export type RfqStatusValue =
  | string
  | { title?: string; id?: number }
  | null
  | undefined;

export interface RfqStatusToActiveValidationResult {
  allowed: boolean;
  message?: string;
  missingFields?: string[];
}

export const RFQ_ACTIVE_REQUIRES_TECH_PACK_MESSAGE =
  'A Tech Pack Link is required before setting status to Active. / 状态改为 Active 前需要填写 Tech Pack Link。';
export const RFQ_ACTIVE_MISSING_FIELDS_PREFIX =
  'Status cannot be changed to Active. Missing';
export const RFQ_ACTIVE_MISSING_FIELDS_PREFIX_ZH =
  '状态无法改为 Active。缺少';

export interface RfqRequiredField {
  field: string;
  label: string;
  exemptForAllowListedUsers?: boolean;
}

export interface RfqStatusToActiveValidationContext {
  exemptUserIds?: number[];
  currentUserId?: number | null;
  requiredFields?: RfqRequiredField[];
}

/** True when the user may set Active without a tech pack link (config allow-list). */
export function isUserExemptFromTechPackRequirementForActive(
  currentUserId: number | null | undefined,
  exemptUserIds: number[] = []
): boolean {
  if (currentUserId == null) {
    return false;
  }
  const normalizedUserId = Number(currentUserId);
  if (Number.isNaN(normalizedUserId)) {
    return false;
  }
  return exemptUserIds.map((id) => Number(id)).includes(normalizedUserId);
}

/** True when the status value represents Active (by title or known id). */
export function isRfqActiveStatus(status: RfqStatusValue): boolean {
  if (status == null) {
    return false;
  }
  if (typeof status === 'string') {
    return status.trim().toLowerCase() === RFQ_ACTIVE_STATUS_TITLE.toLowerCase();
  }
  const title = status.title?.trim().toLowerCase();
  if (title === RFQ_ACTIVE_STATUS_TITLE.toLowerCase()) {
    return true;
  }
  return status.id === RFQ_ACTIVE_STATUS_ID;
}

/** True when the row has a non-empty tech pack link (not null / "null" / whitespace). */
export function hasRfqTechPackLink(
  rowData: Record<string, unknown> | null | undefined,
  techPackFieldName: string = RFQ_TECH_PACK_LINK_FIELD
): boolean {
  if (!rowData) {
    return false;
  }
  const value = rowData[techPackFieldName];
  if (value == null) {
    return false;
  }
  const normalized = String(value).trim();
  if (!normalized) {
    return false;
  }
  return normalized.toLowerCase() !== 'null';
}

function hasRequiredFieldValue(
  rowData: Record<string, unknown> | null | undefined,
  fieldName: string
): boolean {
  if (!rowData || !fieldName) {
    return false;
  }
  const value = rowData[fieldName];
  if (value == null) {
    return false;
  }
  if (Array.isArray(value)) {
    return value.length > 0;
  }
  if (typeof value === 'object') {
    const maybeRecord = value as Record<string, unknown>;
    if ('title' in maybeRecord) {
      const title = String(maybeRecord.title ?? '').trim();
      return !!title && title.toLowerCase() !== 'null';
    }
    return Object.keys(maybeRecord).length > 0;
  }
  const normalized = String(value).trim();
  return !!normalized && normalized.toLowerCase() !== 'null';
}

export function getMissingRfqActiveRequiredFields(
  rowData: Record<string, unknown> | null | undefined,
  requiredFields: RfqRequiredField[],
  validationContext?: RfqStatusToActiveValidationContext
): string[] {
  const userIsExempt = isUserExemptFromTechPackRequirementForActive(
    validationContext?.currentUserId,
    validationContext?.exemptUserIds ?? []
  );

  return requiredFields
    .filter((field) => {
      if (field.exemptForAllowListedUsers && userIsExempt) {
        return false;
      }
      return !hasRequiredFieldValue(rowData, field.field);
    })
    .map((field) => field.label);
}

export function buildRfqActiveMissingFieldsMessage(missingFields: string[]): string {
  if (missingFields.length === 1 && missingFields[0] === RFQ_TECH_PACK_LINK_FIELD) {
    return RFQ_ACTIVE_REQUIRES_TECH_PACK_MESSAGE;
  }
  const fields = missingFields.join(', ');
  return `${RFQ_ACTIVE_MISSING_FIELDS_PREFIX}: ${fields}. / ${RFQ_ACTIVE_MISSING_FIELDS_PREFIX_ZH}：${fields}。`;
}

/**
 * Blocks changing status to Active when required RFQ fields are missing.
 * Other status transitions are always allowed.
 */
export function canChangeRfqStatusToActive(
  rowData: Record<string, unknown> | null | undefined,
  newStatus: RfqStatusValue,
  techPackFieldName: string = RFQ_TECH_PACK_LINK_FIELD,
  validationContext?: RfqStatusToActiveValidationContext
): RfqStatusToActiveValidationResult {
  if (!isRfqActiveStatus(newStatus)) {
    return { allowed: true };
  }

  const requiredFields = validationContext?.requiredFields ?? [
    {
      field: techPackFieldName,
      label: RFQ_TECH_PACK_LINK_FIELD,
      exemptForAllowListedUsers: true,
    },
  ];
  const missingFields = getMissingRfqActiveRequiredFields(
    rowData,
    requiredFields,
    validationContext
  );

  if (missingFields.length === 0) {
    return { allowed: true };
  }

  return {
    allowed: false,
    message: buildRfqActiveMissingFieldsMessage(missingFields),
    missingFields,
  };
}

