  private isStepColumn(colName: string): boolean {
    const stepField = this.getMasterFiledName('step');
    return colName === 'Step' || (!!stepField && colName === stepField);
  }

  private mapCellValueToObject(params: any, col_name: string): any {
    let newValue = params.newValue;
  
    if (typeof newValue !== 'string') {
      return newValue;
    }
  
    if (this.isStepColumn(col_name)) {
      const stepObject = this.stepList.find((step) => step.RFQStep_title === newValue);
      if (stepObject) {
        newValue = { id: stepObject.RFQStep_id, title: stepObject.RFQStep_title };
      } else {
        const fallback = this.getFactoriesStepValue();
        if (newValue === fallback.title) {
          newValue = { id: fallback.id, title: fallback.title };
        }
      }
    }
  
    if (col_name === 'Delivery Location') {
      const deliveryLocationObject = this.deliveryLocationList.find(dl => dl.deliveryLocation_title === newValue);
      newValue = { id: deliveryLocationObject.deliveryLocation_id, title: deliveryLocationObject.deliveryLocation_title };
    }
  
    params.newValue = newValue;

    return newValue;
  }
  

  private async handleStepValueChange(params: any,col_name: string): Promise<boolean> {
  
    const newValue = this.mapCellValueToObject(params, col_name);
  
    // Guard clauses
    if (!newValue || !newValue.title || newValue.title === params.oldValue) {
      return false;
    }
  
    // Step = 2 → validate mandatory fields
    if (this.isStepColumn(col_name) && newValue.id === 2) {
      const requiredFields: { key: string; label: string }[] = [
        { key: 'case_pack', label: 'Case Pack' },
        { key: 'rfq_group', label: 'RFQ Group' },
        { key: 'quantity', label: 'Quantity' },
        { key: 'customer', label: 'Customer' },
        { key: 'license', label: 'License' },
        { key: 'desc', label: 'Description' },
        { key: 'delivery_location', label: 'Delivery Location' },
      ];
      const missingFields = requiredFields.filter(
        (f) => !params.data[this.getMasterFiledName(f.key)]
      );

      if (missingFields.length > 0) {
        const missingLabels = missingFields.map((f) => f.label).join(', ');
        this._snackBar.open(
          `Please fill required fields: ${missingLabels}. / 请填写必填项：${missingLabels}。`,
          'ok'
        );
        return false;
      }
    }
  
    // Update value locally
    params.data[col_name] = newValue;
    this.applyFactoriesStepUpdatedAt(params.data, col_name, newValue);
  
    // Persist step change
    const res = await firstValueFrom(this.itemService
      .setRFQSteps({ step: newValue, data: params.data }));
  
    // Draft → Active status update (requires tech pack link)
    let autoActivatedStatus: { title: string; id: number } | null = null;
    if (newValue.id === 2 && params.data[this.getMasterFiledName('status')]?.title === 'Draft') {
      const activeStatus = { title: 'Active', id: 1 };
      const validation = canChangeRfqStatusToActive(
        params.data,
        activeStatus,
        this.getMasterFiledName('tech_pack_url'),
        this.getRfqStatusToActiveValidationContext()
      );
      if (validation.allowed) {
        params.data[this.getMasterFiledName('status')] = activeStatus;
        autoActivatedStatus = activeStatus;
      } else if (validation.message) {
        this._snackBar.open(validation.message, 'ok', { duration: 10000 });
      }
    }

    if (this.isStepColumn(col_name)) {
      await this.persistStepChangeAndRefreshGrid(params.data);
      if (autoActivatedStatus) {
        this.notifyRfqItemStatusChanged(autoActivatedStatus, params.data);
      }
    }
  
    return true;
  }

  private getStatusBlockedTooltip(rowData: any): string {
    const statusField = this.getMasterFiledName('status');
    const currentStatus = rowData?.[statusField];
    const currentTitle = currentStatus?.title ?? currentStatus?.RFQItemStatus_title ?? currentStatus;
    if (String(currentTitle ?? '').trim().toLowerCase() === 'active') {
      return '';
    }
    const validation = canChangeRfqStatusToActive(
      rowData,
      { title: 'Active', id: 1 },
      this.getMasterFiledName('tech_pack_url'),
      this.getRfqStatusToActiveValidationContext()
    );
    return validation.allowed ? '' : validation.message ?? '';
  }

