+      this.getRfqStatusToActiveValidationContextWithoutTechPack()
+    );
+    if (!blockingValidation.allowed) {
+      this._snackBar.open(blockingValidation.message, 'ok', { duration: 10000 });
+      return false;
+    }
+
+    const rowsMissingTechPack = this.getDraftRowsNeedingTechPackWarning([rowData], newStatus);
+    if (!rowsMissingTechPack.length) {
+      return true;
+    }
+
+    return await this.confirmProceedWithoutTechPack(rowsMissingTechPack.length);
+  }
+
+  private getDraftRowsNeedingTechPackWarning(rows: any[], newStatus: any): any[] {
+    if (!this.isActiveStatusValue(newStatus)) {
+      return [];
+    }
+    return rows.filter((rowData) => {
+      if (!this.isDraftStatusValue(rowData?.[this.getMasterFiledName('status')])) {
+        return false;
+      }
+      const validation = canChangeRfqStatusToActive(
+        rowData,
+        newStatus,
+        this.getMasterFiledName('tech_pack_url'),
+        this.getTechPackOnlyValidationContext()
+      );
+      return !validation.allowed && validation.missingFields?.includes(RFQ_TECH_PACK_LINK_FIELD);
+    });
+  }
+
+  private async confirmProceedWithoutTechPack(count: number): Promise<boolean> {
+    const dialogRef = this.dialog.open(TechPackWarningDialogComponent, {
+      width: '420px',
+      disableClose: true,
+      data: { count },
+    });
+    return !!(await firstValueFrom(dialogRef.afterClosed()));
+  }
+
+  private getRfqStatusToActiveValidationContextWithoutTechPack(): RfqStatusToActiveValidationContext {
+    const techPackField = this.getMasterFiledName('tech_pack_url');
+    return {
+      exemptUserIds: this.allowActiveWithoutTechPackUserIds,
+      currentUserId: this.currentUserId,
+      requiredFields: this.getActiveStatusRequiredFields().filter(
+        (field) => field.field !== techPackField
+      ),
+    };
+  }
+
+  private getTechPackOnlyValidationContext(): RfqStatusToActiveValidationContext {
+    return {
+      exemptUserIds: this.allowActiveWithoutTechPackUserIds,
+      currentUserId: this.currentUserId,
+      requiredFields: [
+        {
+          field: this.getMasterFiledName('tech_pack_url'),
+          label: RFQ_TECH_PACK_LINK_FIELD,
+          exemptForAllowListedUsers: true,
+        },
+      ],
+    };
+  }
+
+  private isActiveStatusValue(status: any): boolean {
+    return this.getStatusTitle(status).toLowerCase() === 'active' || Number(status?.id ?? status?.RFQItemStatus_id) === 1;
+  }
+
+  private isDraftStatusValue(status: any): boolean {
+    return this.getStatusTitle(status).toLowerCase() === 'draft';
+  }
+
+  private getStatusTitle(status: any): string {
+    if (typeof status === 'string') {
+      return status.trim();
+    }
+    return String(status?.title ?? status?.RFQItemStatus_title ?? '').trim();
+  }
+
+  compareStatusValues = (a: any, b: any): boolean => {
+    if (a === b) {
+      return true;
+    }
+    const aId = a?.RFQItemStatus_id ?? a?.id;
+    const bId = b?.RFQItemStatus_id ?? b?.id;
+    return aId != null && bId != null ? Number(aId) === Number(bId) : this.getStatusTitle(a) === this.getStatusTitle(b);
+  };
+
+  private normalizeStatusValue(status: any): { title: string; id: number | null } | null {
+    const title = this.getStatusTitle(status);
+    if (!title) {
+      return null;
+    }
+    return {
+      title,
+      id: status?.RFQItemStatus_id ?? status?.id ?? null,
+    };
+  }
+
+  private getBulkStatusTargetRowNodes(): any[] {
+    if (!this.gridApi) {
+      return [];
+    }
+
+    const nodesById = new Map<string, any>();
+    const addNode = (node: any) => {
+      if (!node?.data) {
+        return;
+      }
+      const key = String(node.id ?? node.data['Price Code'] ?? node.rowIndex);
+      nodesById.set(key, node);
+    };
+
+    (this.gridApi.getSelectedNodes?.() ?? []).forEach(addNode);
+
+    const ranges = this.gridApi.getCellRanges?.() ?? [];
+    ranges.forEach((range: any) => {
+      const includesStatus = range.columns?.some((column: any) => column.getColId?.() === 'status');
+      if (!includesStatus || !range.startRow || !range.endRow) {
+        return;
+      }
+      const startRowIdx = Math.min(range.startRow.rowIndex, range.endRow.rowIndex);
+      const endRowIdx = Math.max(range.startRow.rowIndex, range.endRow.rowIndex);
+      for (let rowIdx = startRowIdx; rowIdx <= endRowIdx; rowIdx++) {
+        addNode(this.gridApi.getDisplayedRowAtIndex?.(rowIdx));
+      }
+    });
+
+    return Array.from(nodesById.values());
+  }
+
+  async onApplyBulkStatus(): Promise<void> {
+    const status = this.normalizeStatusValue(this.selectedBulkStatus);
+    if (!status) {
+      this._snackBar.open('Choose a status first.', 'Close', { duration: 3500 });
+      return;
+    }
+
+    const rowNodes = this.getBulkStatusTargetRowNodes();
+    if (!rowNodes.length) {
+      this._snackBar.open('Select rows or Status cells first.', 'Close', { duration: 3500 });
+      return;
+    }
+
+    const blockedRows = rowNodes.filter(({ data }) => {
+      const validation = canChangeRfqStatusToActive(
+        data,
+        status,
+        this.getMasterFiledName('tech_pack_url'),
+        this.getRfqStatusToActiveValidationContextWithoutTechPack()
+      );
+      return !validation.allowed;
+    });
+    if (blockedRows.length) {
+      this._snackBar.open(
+        `Cannot apply Active. ${blockedRows.length} selected row(s) are missing required fields other than Tech Pack Link.`,
+        'Close',
+        { duration: 10000 }
+      );
+      return;
+    }
+
+    const rowsMissingTechPack = this.getDraftRowsNeedingTechPackWarning(
+      rowNodes.map((node) => node.data),
+      status
+    );
+    if (rowsMissingTechPack.length && !(await this.confirmProceedWithoutTechPack(rowsMissingTechPack.length))) {
+      return;
+    }
+
+    const statusField = this.getMasterFiledName('status');
+    this.bulkStatusUpdating = true;
+    try {
+      for (const node of rowNodes) {
+        node.data[statusField] = { ...status };
+        await firstValueFrom(this.itemService.updateRfqItem(node.data));
+        node.data['Date Modified'] = new Date().toISOString();
+      }
+      this.gridApi.applyTransaction?.({ update: rowNodes.map((node) => node.data) });
+      this.gridApi.refreshCells?.({ rowNodes, columns: ['status'], force: true });
+      this._snackBar.open(`Status updated for ${rowNodes.length} row(s).`, 'Close', { duration: 3500 });
+    } catch (err) {
+      console.error('[Rfq] bulk status update failed:', err);
+      this._snackBar.open('Failed to update status for the selected rows.', 'Close', { duration: 5000 });
+    } finally {
+      this.bulkStatusUpdating = false;
+    }
+  }
+
